
"use client"

import { useState, useEffect, useCallback, useMemo, useRef } from "react";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Radio, ShieldAlert, LocateFixed, Radar, Loader2, AlertTriangle, Settings } from "lucide-react";
import { GoogleMap, useJsApiLoader, MarkerF, CircleF } from "@react-google-maps/api";
import { cn } from "@/lib/utils";

const KOSOVO_CENTER = { lat: 42.6629, lng: 21.1655 }; // Prishtina

const mapContainerStyle = {
  width: "100%",
  height: "100%",
};

const darkMapOptions = {
  disableDefaultUI: true,
  zoomControl: false,
  styles: [
    { elementType: "geometry", stylers: [{ color: "#0f172a" }] },
    { elementType: "labels.text.stroke", stylers: [{ color: "#0f172a" }] },
    { elementType: "labels.text.fill", stylers: [{ color: "#64748b" }] },
    { featureType: "administrative.locality", elementType: "labels.text.fill", stylers: [{ color: "#94a3b8" }] },
    { featureType: "poi", elementType: "labels.text.fill", stylers: [{ color: "#64748b" }] },
    { featureType: "road", elementType: "geometry", stylers: [{ color: "#1e293b" }] },
    { featureType: "road", elementType: "geometry.stroke", stylers: [{ color: "#334155" }] },
    { featureType: "road", elementType: "labels.text.fill", stylers: [{ color: "#94a3b8" }] },
    { featureType: "road.highway", elementType: "geometry", stylers: [{ color: "#334155" }] },
    { featureType: "road.highway", elementType: "geometry.stroke", stylers: [{ color: "#475569" }] },
    { featureType: "water", elementType: "geometry", stylers: [{ color: "#020617" }] },
  ],
};

export default function ExplorePage() {
  const [location, setLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isWatching, setIsWatching] = useState(false);
  const [map, setMap] = useState<google.maps.Map | null>(null);
  const hasCenteredInitially = useRef(false);

  const googleMapsApiKey = process.env.NEXT_PUBLIC_GOOGLE_MAPS_API_KEY || "AIzaSyDFuy7SBm271JjuXyltNB";

  const { isLoaded, loadError } = useJsApiLoader({
    id: 'google-map-script',
    googleMapsApiKey: googleMapsApiKey,
  });

  const onUnmount = useCallback(function callback() {
    setMap(null);
  }, []);

  const onMapLoad = useCallback((mapInstance: google.maps.Map) => {
    setMap(mapInstance);
  }, []);

  useEffect(() => {
    if (typeof window === "undefined" || !navigator.geolocation) {
      setError("Gjeolokacioni nuk mbështetet");
      return;
    }

    const watchId = navigator.geolocation.watchPosition(
      (position) => {
        const newPos = {
          lat: position.coords.latitude,
          lng: position.coords.longitude,
        };
        setLocation(newPos);
        setIsWatching(true);
        
        if (map && !hasCenteredInitially.current) {
          map.panTo(newPos);
          hasCenteredInitially.current = true;
        }
      },
      (err) => {
        setError(err.message);
        setIsWatching(false);
      },
      { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 }
    );

    return () => navigator.geolocation.clearWatch(watchId);
  }, [map]);

  const radarMarkers = useMemo(() => [
    { position: { lat: 42.665, lng: 21.160 }, label: "Njësi Mobile", color: "red" },
    { position: { lat: 42.600, lng: 21.100 }, label: "Kamerë Shpejtësie", color: "orange" },
    { position: { lat: 42.700, lng: 21.200 }, label: "Patrullë Autostrade", color: "red" }
  ], []);

  if (loadError) {
    return (
      <div className="flex flex-col min-h-screen bg-background text-foreground pb-24 items-center justify-center p-8 text-center">
        <div className="w-20 h-20 rounded-full bg-red-500/10 flex items-center justify-center mb-6">
          <AlertTriangle className="w-10 h-10 text-red-500" />
        </div>
        <h1 className="text-xl font-black italic uppercase tracking-tighter mb-2">GABIM I KONFIGURIMIT TË HARTËS</h1>
        <p className="text-sm text-muted-foreground mb-8">
          Çelësi i API-së së Google Maps duket se është i pasaktë ose i pavlefshëm. Sigurohuni që keni aktivizuar "Maps JavaScript API" në Google Cloud Console.
        </p>
        <div className="glass p-6 rounded-2xl border-white/10 w-full max-w-sm text-left space-y-4">
          <div className="flex items-center gap-3">
            <Settings className="w-5 h-5 text-accent" />
            <span className="text-xs font-bold uppercase tracking-widest text-accent">Veprim i Kërkuar</span>
          </div>
          <p className="text-[11px] font-medium leading-relaxed">
            Nëse sapo keni krijuar çelësin, mund të duhen deri në 5 minuta për t'u aktivizuar. Gjithashtu kontrolloni nëse ka kufizime për URL-të.
          </p>
          <Button variant="outline" className="w-full text-[10px] font-black uppercase tracking-widest h-10" onClick={() => window.location.reload()}>
            PROVO PËRSËRI
          </Button>
        </div>
        <BottomNav />
      </div>
    );
  }

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground pb-24 relative overflow-hidden">
      <div className="absolute inset-0 z-0">
        {isLoaded ? (
          <GoogleMap
            mapContainerStyle={mapContainerStyle}
            center={location || KOSOVO_CENTER}
            zoom={13}
            onLoad={onMapLoad}
            onUnmount={onUnmount}
            options={darkMapOptions as google.maps.MapOptions}
          >
            {location && (
              <>
                <MarkerF
                  position={location}
                  icon={{
                    path: google.maps.SymbolPath.CIRCLE,
                    scale: 8,
                    fillColor: "#06b6d4",
                    fillOpacity: 1,
                    strokeWeight: 2,
                    strokeColor: "#ffffff",
                  }}
                />
                <CircleF
                  center={location}
                  radius={500}
                  options={{
                    fillColor: "#06b6d4",
                    fillOpacity: 0.1,
                    strokeColor: "#06b6d4",
                    strokeOpacity: 0.3,
                    strokeWeight: 1,
                  }}
                />
              </>
            )}

            {radarMarkers.map((marker, i) => (
              <MarkerF
                key={i}
                position={marker.position}
                label={{
                  text: marker.label,
                  color: "#ffffff",
                  fontSize: "10px",
                  className: "mt-8 font-black uppercase bg-black/80 px-2 py-1 rounded"
                }}
                icon={{
                  path: google.maps.SymbolPath.BACKWARD_CLOSED_ARROW,
                  scale: 5,
                  fillColor: marker.color === "red" ? "#ef4444" : "#f97316",
                  fillOpacity: 1,
                  strokeWeight: 0,
                }}
              />
            ))}
          </GoogleMap>
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center bg-card/20 animate-pulse">
            <Loader2 className="w-12 h-12 text-accent animate-spin mb-4" />
            <p className="text-accent font-black tracking-widest uppercase italic">DUKE U LIDHUR...</p>
          </div>
        )}
        <div className="absolute inset-0 bg-gradient-to-b from-transparent via-accent/5 to-transparent h-32 w-full animate-scan z-10 pointer-events-none" />
      </div>

      <div className="relative z-40 p-6 flex flex-col h-full gap-4 pointer-events-none">
        <div className="flex justify-between items-start w-full">
          <div className="glass p-4 rounded-2xl border-white/10 flex flex-col gap-1 w-56 shadow-2xl backdrop-blur-xl bg-black/40 pointer-events-auto">
            <div className="flex items-center gap-2 mb-1">
              <Radar className={cn("w-4 h-4 text-accent", isWatching && "animate-spin")} />
              <span className="text-[10px] font-black text-accent uppercase tracking-widest">RADARI I GARËS LIVE</span>
            </div>
            {location ? (
              <div className="space-y-1">
                <p className="text-[10px] font-bold text-muted-foreground uppercase leading-none">Pozicioni GPS</p>
                <p className="text-xs font-mono font-bold italic text-white leading-none">
                  {location.lat.toFixed(6)}° N<br/>
                  {location.lng.toFixed(6)}° E
                </p>
              </div>
            ) : (
              <p className="text-xs font-bold text-red-400 animate-pulse">
                {error ? `Gabim GPS: ${error}` : "Duke u lidhur..."}
              </p>
            )}
          </div>
          <Button 
            size="icon" 
            variant="outline" 
            onClick={() => {
              if (location && map) {
                map.panTo(location);
                map.setZoom(15);
              }
            }}
            className="rounded-2xl glass border-white/10 w-12 h-12 shadow-2xl hover:bg-accent/20 backdrop-blur-xl bg-black/40 pointer-events-auto"
          >
            <LocateFixed className="w-5 h-5 text-accent" />
          </Button>
        </div>

        <div className="mt-auto space-y-3 mb-6">
          <div className="glass border-red-500/40 rounded-3xl p-5 shadow-[0_0_50px_rgba(239,68,68,0.3)] animate-pulse border-2 backdrop-blur-xl bg-black/60 pointer-events-auto">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-2xl bg-red-500/20 flex items-center justify-center border border-red-500/50">
                <ShieldAlert className="w-7 h-7 text-red-500" />
              </div>
              <div className="flex-1">
                <div className="flex items-center justify-between">
                  <h3 className="text-base font-black italic uppercase tracking-tighter text-red-500">ZONË E RREZIKSHME</h3>
                  <Badge className="bg-red-500 text-white font-bold text-[8px] h-4">KRITIKE</Badge>
                </div>
                <p className="text-sm font-bold opacity-90 leading-tight">Njësi mobile e policisë u detektua brenda 2km</p>
                <p className="text-[10px] font-bold uppercase opacity-50 mt-1">Zona Ferizaj-Prishtinë</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      <BottomNav />
    </div>
  );
}
